package com.yottastudios.ns.collabspace.space.service.impl;

import com.yottastudios.ns.collabspace.base.enums.DatabaseException;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.core.util.ExceptionUtil;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.shared.config.properties.ConstProperties;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import org.springframework.data.redis.core.RedisTemplate;
import com.yottastudios.ns.collabspace.space.entity.SpaceEntity;
import com.yottastudios.ns.collabspace.space.manager.query.SpaceQueryManager;
import com.yottastudios.ns.collabspace.space.service.ISpaceService;
import com.yottastudios.ns.collabspace.space.service.IWorkspaceApplyService;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.apache.commons.lang3.StringUtils;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.concurrent.TimeUnit;

/**
 * 空间站成员申请服务实现.
 * 1. 校验 workspaceId 有效性及当前用户是否已为成员
 * 2. 获取用户花名、空间站名称
 * 3. 获取空间站管理员列表
 * 4. 向管理员发送 knock/mm 消息
 */
@Slf4j
@Service
public class WorkspaceApplyServiceImpl implements IWorkspaceApplyService {

    @Resource
    private ISpaceService spaceService;

    @Resource
    private SpaceQueryManager spaceQueryManager;

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Resource
    private ConstProperties constProperties;

    @Resource
    private WorkspaceApplyNotifyService workspaceApplyNotifyService;

    @Resource
    private RedisTemplate<String, Object> redisTemplate;

    private static final String REDIS_KEY_PREFIX = "workspace_apply:";
    private static final long COOLDOWN_HOURS = 1;

    @Override
    public void applyMembership(String workspaceId) {
        log.info("[1822-WorkspaceApply] apply entry workspaceId={}", workspaceId);
        if (StringUtils.isBlank(workspaceId)) {
            throw new BusinessException("workspaceId 无效");
        }

        Long userId = SessionContext.getUserId();
        log.info("[1822-WorkspaceApply] applicant userId={}", userId);

        SpaceEntity spaceEntity = spaceService.listByIds(List.of(workspaceId), true)
                .stream()
                .findFirst()
                .orElse(null);
        ExceptionUtil.isNotNull(spaceEntity, DatabaseException.QUERY_EMPTY_BY_ID);

        if (Boolean.TRUE.equals(spaceEntity.getIsForbid())) {
            throw new BusinessException("空间站不存在或已禁用");
        }

        if (spaceQueryManager.isUserInSpace(userId, workspaceId)) {
            throw new BusinessException("您已是该空间站成员");
        }

        UserSimpleInfoVo applicant = apitableGrpcClientService.getUserById(userId);
        String applicantNickName = applicant != null && StringUtils.isNotBlank(applicant.getNickName())
                ? applicant.getNickName()
                : "用户" + userId;

        String spaceName = StringUtils.isNotBlank(spaceEntity.getName()) ? spaceEntity.getName() : workspaceId;
        log.info("[1822-WorkspaceApply] applicantNickName={} spaceName={}", applicantNickName, spaceName);

        List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(workspaceId);
        if (CollectionUtils.isEmpty(adminUserIds)) {
            log.warn("[1822-WorkspaceApply] no admins workspaceId={}", workspaceId);
            return;
        }
        log.info("[1822-WorkspaceApply] adminCount={}", adminUserIds.size());

        String redisKey = REDIS_KEY_PREFIX + userId + ":" + workspaceId;
        Boolean firstApply = redisTemplate.opsForValue().setIfAbsent(redisKey, "1", COOLDOWN_HOURS, TimeUnit.HOURS);
        if (Boolean.FALSE.equals(firstApply)) {
            log.info("[1822-WorkspaceApply] duplicate blocked userId={} workspaceId={} cooldown={}h", userId, workspaceId, COOLDOWN_HOURS);
            throw new BusinessException("您已申请过，请等待管理员处理，请勿重复申请");
        }

        String managementUrl = buildManagementUrl();
        String message = String.format("[%s]申请加入[%s]，请在空间站管理后台添加成员，点击直达空间站管理后台:%s",
                applicantNickName, spaceName, managementUrl);
        log.info("[1822-WorkspaceApply] notify messageLen={} managementUrl={}", message != null ? message.length() : 0, managementUrl);

        workspaceApplyNotifyService.notifyAdmins(workspaceId, spaceName, adminUserIds, message);
        log.info("[1822-WorkspaceApply] apply done workspaceId={}", workspaceId);
    }

    private String buildManagementUrl() {
        String domain = constProperties.getServerDomain();
        if (StringUtils.isBlank(domain)) {
            return "";
        }
        String base = domain.endsWith("/") ? domain.substring(0, domain.length() - 1) : domain;
        return base + "/#/user-backend/space-roles";
    }
}

