package com.yottastudios.ns.collabspace.control.controller;

import com.yottastudios.ns.collabspace.control.service.IPermissionRequestService;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RestController;

import java.util.Map;

/**
 * Notification approval controller.
 * Handles permission request approval actions: approve, reject, ignore, reapprove.
 * All four require validating against collabspace permission_request table (migrated from apitable).
 * notificationId is the apitable player_notification.id.
 * This controller resolves requestId via gRPC call to apitable before delegating to service.
 */
@Slf4j
@RestController
@Tag(name = "Notification Approval")
@ApiResource(path = "/player/notification")
public class NotificationApprovalController {

    private static final String DOCUMENT_PERMISSION_REQUEST = "document_permission_request";

    @Resource
    private IPermissionRequestService permissionRequestService;

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    /**
     * Approve a permission request.
     */
    @PostResource(path = "/{notificationId}/approve", requiredPermission = false)
    @Operation(summary = "Approve permission request")
    public ResponseData<Void> approve(@PathVariable("notificationId") Long notificationId) {
        Long userId = SessionContext.getUserId();
        log.info("[1822-Approval] APPROVE entry notificationId={} approverUserId={}", notificationId, userId);
        String requestId = resolveRequestId(notificationId, userId);
        permissionRequestService.approveByRequestId(requestId, notificationId, userId);
        return ResponseData.success();
    }

    /**
     * Reject a permission request.
     */
    @PostResource(path = "/{notificationId}/reject", requiredPermission = false)
    @Operation(summary = "Reject permission request")
    public ResponseData<Void> reject(@PathVariable("notificationId") Long notificationId) {
        Long userId = SessionContext.getUserId();
        log.info("[1822-Approval] REJECT entry notificationId={} approverUserId={}", notificationId, userId);
        String requestId = resolveRequestId(notificationId, userId);
        permissionRequestService.rejectByRequestId(requestId, notificationId, userId);
        return ResponseData.success();
    }

    /**
     * Ignore - mark notification as read.
     */
    @PostResource(path = "/{notificationId}/ignore", requiredPermission = false)
    @Operation(summary = "Ignore permission request")
    public ResponseData<Void> ignore(@PathVariable("notificationId") Long notificationId) {
        Long userId = SessionContext.getUserId();
        log.info("[1822-Approval] IGNORE entry notificationId={} approverUserId={}", notificationId, userId);
        String requestId = resolveRequestId(notificationId, userId);
        permissionRequestService.ignoreByRequestId(requestId, notificationId, userId);
        return ResponseData.success();
    }

    /**
     * Reapprove - mark notification as unread so admin can re-handle.
     */
    @PostResource(path = "/{notificationId}/reapprove", requiredPermission = false)
    @Operation(summary = "Reapprove (un-ignore) permission request")
    public ResponseData<Void> reapprove(@PathVariable("notificationId") Long notificationId) {
        Long userId = SessionContext.getUserId();
        log.info("[1822-Approval] REAPPROVE entry notificationId={} approverUserId={}", notificationId, userId);
        String requestId = resolveRequestId(notificationId, userId);
        permissionRequestService.reapproveByRequestId(requestId, notificationId, userId);
        return ResponseData.success();
    }

    /**
     * 通过 gRPC 到 apitable 查通知 body extras，取出 requestId.
     */
    private String resolveRequestId(Long notificationId, Long approverUserId) {
        Map<String, String> extras = apitableGrpcClientService.getNotificationExtras(notificationId, approverUserId);
        if (extras == null || extras.isEmpty()) {
            log.warn("[1822-Approval] resolveRequestId: getNotificationExtras returned empty notificationId={} approverUserId={}",
                    notificationId, approverUserId);
            throw new BusinessException(
                com.yottastudios.ns.collabspace.control.enums.PermissionRequestException.NOTIFICATION_NOT_VALID);
        }
        String templateId = extras.get("templateId");
        if (!DOCUMENT_PERMISSION_REQUEST.equals(templateId)) {
            log.warn("[1822-Approval] resolveRequestId: not a permission request notification notificationId={} templateId={}",
                    notificationId, templateId);
            throw new BusinessException(
                com.yottastudios.ns.collabspace.control.enums.PermissionRequestException.NOTIFICATION_NOT_VALID);
        }
        String requestId = extras.get("requestId");
        if (requestId == null || requestId.isBlank()) {
            log.warn("[1822-Approval] resolveRequestId: requestId missing in extras notificationId={}",
                    notificationId);
            throw new BusinessException(
                com.yottastudios.ns.collabspace.control.enums.PermissionRequestException.NOTIFICATION_NOT_VALID);
        }
        log.info("[1822-Approval] resolveRequestId ok notificationId={} requestId={}", notificationId, requestId);
        return requestId;
    }
}

