183→    private SpaceNodeEntity getSpaceNodeByNodeIdSafe(String nodeId) {
184→        if (nodeId == null) return null;
185→        // Always try by appSpaceNodeId column first (including deleted rows).
186→        List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIdsAllStatus(Collections.singletonList(nodeId));
187→        if (CollUtil.isNotEmpty(nodes)) return nodes.get(0);
188→        // Fallback: treat as pk if numeric — only reached for non-OnlyOffice nodes.
189→        if (nodeId.matches("^\\d+$")) {
190→            return spaceNodeService.getByIdAllStatus(Long.parseLong(nodeId));
191→        }
192→        return null;
193→    }
