439→        // Update notification extras in apitable (via gRPC) — updates shared notification record for all recipients
440→        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_REJECTED,
441→            approverUuid, approverNickName);
442→
443→        // Mark approver's own notification as read
