456→    @Override
457→    public void ignoreByRequestId(String requestId, Long notificationId, Long approverUserId) {
458→        validateRequestForApprover(requestId, approverUserId);
459→        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);
460→        log.info("[1822-PermApply] IGNORE requestId={} notificationId={} approverUserId={}", requestId, notificationId, approverUserId);
461→    }
462→
463→    @Override
464→    public void reapproveByRequestId(String requestId, Long notificationId, Long approverUserId) {
465→        validateRequestForApprover(requestId, approverUserId);
466→        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, false);
467→        log.info("[1822-PermApply] REAPPROVE requestId={} notificationId={} approverUserId={}", requestId, notificationId, approverUserId);
468→    }
469→
470→    // ========== Validation Helpers ==========
471→
472→    /**
473→     * Validates requestId exists and approver is admin. Does NOT check PENDING status.
474→     * Used for reapprove, which can act on already-processed requests.
475→     */
476→    private void validateRequestForApprover(String requestId, Long approverUserId) {
477→        if (requestId == null || requestId.isBlank()) {
478→            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
479→        }
480→        PermissionRequestEntity request = baseMapper.selectById(requestId);
481→        if (request == null) {
482→            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
483→            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
484→        }
485→        validateApproverIsAuthorized(approverUserId, request.getSpaceId(), request.getDocumentId());
486→    }
487→
488→    private PermissionRequestEntity validateAndGetRequest(String requestId, Long approverUserId) {
489→        if (requestId == null || requestId.isBlank()) {
490→            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
491→        }
492→        PermissionRequestEntity request = baseMapper.selectById(requestId);
493→        if (request == null) {
494→            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
495→            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
496→        }
497→        if (!STATUS_PENDING.equals(request.getStatus())) {
498→            log.warn("[1822-PermApply] validate alreadyProcessed requestId={} status={}",
499→                request.getId(), request.getStatus());
500→            ExceptionUtil.isTrue(false, PermissionRequestException.REQUEST_ALREADY_PROCESSED);
501→        }
502→        validateApproverIsAuthorized(approverUserId, request.getSpaceId(), request.getDocumentId());
503→        return request;
504→    }
505→
506→    /**
507→     * Approver is authorized if they are a space admin (MANAGE_WORKBENCH) OR a document manager (MANAGE role on document).
508→     * Both groups receive the permission-apply notification and should be able to act on it.
509→     */
510→    private void validateApproverIsAuthorized(Long approverUserId, String spaceId, String documentId) {
511→        boolean isSpaceAdmin = spaceQueryManager.isUserSpaceAdmin(approverUserId, spaceId);
512→        if (isSpaceAdmin) {
513→            log.info("[1822-PermApply] validateApprover passed as spaceAdmin approverUserId={} spaceId={}", approverUserId, spaceId);
514→            return;
515→        }
516→        List<Long> docManagers = getDocumentManagerUserIds(documentId, spaceId);
517→        boolean isDocManager = docManagers.contains(approverUserId);
518→        log.info("[1822-PermApply] validateApprover isSpaceAdmin={} isDocManager={} approverUserId={} documentId={}",
519→            isSpaceAdmin, isDocManager, approverUserId, documentId);
520→        ExceptionUtil.isTrue(isDocManager, PermissionRequestException.INSUFFICIENT_PERMISSIONS);
521→    }
522→
523→    private UserSimpleInfoVo getApproverInfo(Long approverUserId) {
524→        try {
525→            return apitableGrpcClientService.getUserById(approverUserId);
526→        } catch (Exception e) {
527→            return null;
528→        }
529→    }
530→
531→    private Long parseSpaceNodeId(String documentId) {
532→        if (documentId == null) return null;
533→        // Always look up by appSpaceNodeId column first.
534→        // OnlyOffice nodes (PPT/Excel/Word) use a numeric OnlyOffice fileId as appSpaceNodeId,
535→        // which must NOT be treated as the collabspace pk.
536→        Long byAppNodeId = getSpaceNodeIdByAppNodeId(documentId);
537→        if (byAppNodeId != null) return byAppNodeId;
538→        // Fallback: if documentId is a pure numeric string, treat as spaceNodeId pk.
539→        try {
540→            return Long.parseLong(documentId);
541→        } catch (NumberFormatException e) {
542→            return null;
543→        }
544→    }
545→
546→    private Long getSpaceNodeIdByAppNodeId(String appNodeId) {
547→        try {
548→            List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIdsAllStatus(Collections.singletonList(appNodeId));
549→            if (CollUtil.isNotEmpty(nodes)) {
550→                return nodes.get(0).getId();
551→            }
552→        } catch (Exception e) {
553→            log.warn("[1822-PermApply] getSpaceNodeIdByAppNodeId failed appNodeId={}", appNodeId, e);
554→        }
555→        return null;
556→    }
557→
558→    /**
559→     * Returns the collabspace userIds of all users who have explicit MANAGE permission on the document.
560→     * Handles both member-type (individual) and team-type (department) unit entries in control_role.
561→     */
562→    private List<Long> getDocumentManagerUserIds(String documentId, String spaceId) {
563→        try {
564→            Long spaceNodeId = parseSpaceNodeId(documentId);
565→            if (spaceNodeId == null) return List.of();
566→
567→            List<ControlRoleEntity> roles = controlRoleService.getByControlId(spaceNodeId.toString());
568→            List<Long> managerUnitIds = roles.stream()
569→                .filter(r -> MANAGER.equals(r.getRoleCode()))
570→                .map(ControlRoleEntity::getUnitId)
571→                .toList();
572→
573→            if (CollUtil.isEmpty(managerUnitIds)) return List.of();
574→
575→            List<NodeRoleUnit> nodeRoleUnits = apitableGrpcClientService.getNodeRoleUnitList(spaceId, managerUnitIds);
576→
577→            Set<Long> userIds = new HashSet<>();
578→            List<Long> memberTypeRefIds = new ArrayList<>(); // memberId for unitType=3
579→
580→            for (NodeRoleUnit unit : nodeRoleUnits) {
581→                if (unit.getUnitRefId() == null) continue;
582→                Integer unitType = unit.getUnitType();
583→                if (unitType != null && unitType == 1) {
584→                    // Team/department: expand to all members
585→                    List<UserSimpleInfoVo> members = apitableGrpcClientService.selectMembersByTeamId(spaceId, unit.getUnitRefId());
586→                    members.stream().filter(m -> m.getId() != null).forEach(m -> userIds.add(m.getId()));
587→                } else if (unitType != null && unitType == 3) {
588→                    // Individual member: collect memberId for batch email lookup
589→                    memberTypeRefIds.add(unit.getUnitRefId());
590→                }
591→            }
592→
593→            // Resolve member-type units: memberId → email → userId
594→            if (!memberTypeRefIds.isEmpty()) {
595→                IPage<SpaceMemberVo> memberPage = apitableGrpcClientService.getSpaceMembers(spaceId, 1, 999);
596→                Map<String, String> memberIdToEmail = memberPage.getRecords().stream()
597→                    .filter(m -> m.getMemberId() != null && m.getEmail() != null)
598→                    .collect(Collectors.toMap(SpaceMemberVo::getMemberId, SpaceMemberVo::getEmail, (a, b) -> a));
599→
600→                List<String> emails = memberTypeRefIds.stream()
601→                    .map(refId -> memberIdToEmail.get(String.valueOf(refId)))
602→                    .filter(Objects::nonNull)
603→                    .toList();
604→
605→                if (!emails.isEmpty()) {
606→                    apitableGrpcClientService.getUserByEmails(emails).stream()
607→                        .filter(u -> u.getId() != null)
608→                        .forEach(u -> userIds.add(u.getId()));
609→                }
610→            }
611→
612→            log.info("[1822-PermApply] getDocumentManagerUserIds documentId={} managerUnitCount={} resolvedUserCount={}",
613→                documentId, managerUnitIds.size(), userIds.size());
614→            return new ArrayList<>(userIds);
615→        } catch (Exception e) {
616→            log.warn("[1822-PermApply] getDocumentManagerUserIds failed documentId={} error={}", documentId, e.getMessage());
617→            return List.of();
618→        }
619→    }
620→
621→    /**
622→     * After one admin approves/rejects, mark all other admin and doc-manager recipients' notifications as read.
623→     * The apply notification is a shared record in apitable — the same notificationId covers all recipients,
624→     * so setNotificationRead(notificationId, otherUserId, true) marks it read for each of them individually.
625→     */
626→    private void markOtherRecipientNotificationsRead(Long notificationId, PermissionRequestEntity request,
627→                                                      Long approverUserId) {
628→        try {
629→            List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(request.getSpaceId());
630→            List<Long> docManagerUserIds = getDocumentManagerUserIds(request.getDocumentId(), request.getSpaceId());
631→
632→            Set<Long> others = new LinkedHashSet<>();
633→            others.addAll(adminUserIds);
634→            others.addAll(docManagerUserIds);
635→            others.remove(request.getApplicantUserId());
636→            others.remove(approverUserId);
637→
638→            for (Long userId : others) {
639→                apitableGrpcClientService.setNotificationRead(notificationId, userId, true);
640→            }
641→            log.info("[1822-PermApply] markOtherRecipients notificationId={} count={} requestId={}",
642→                notificationId, others.size(), request.getId());
643→        } catch (Exception e) {
644→            log.warn("[1822-PermApply] markOtherRecipients failed notificationId={} requestId={} error={}",
645→                notificationId, request.getId(), e.getMessage());
646→        }
647→    }
648→
649→    private String mapPermissionTypeToNodeRole(String requestedPermissionType) {
650→        return switch (requestedPermissionType) {
651→            case "READ" -> READER;
652→            case "EDIT" -> EDITOR;
653→            case "MANAGE" -> MANAGER;
654→            default -> READER;
655→        };
656→    }
657→
658→    private String mapPermissionTypeToLabel(String requestedPermissionType) {
659→        if (requestedPermissionType == null) return "";
660→        return switch (requestedPermissionType) {
661→            case "READ" -> "查看";
662→            case "EDIT" -> "编辑";
663→            case "MANAGE" -> "管理";
664→            default -> requestedPermissionType;
665→        };
666→    }
667→
668→    @Async
669→    public void notifyApplicantResultAsync(PermissionRequestEntity request, String status,
670→                                            String approverUuid, String approverNickName) {
671→        try {
672→            String templateId = STATUS_APPROVED.equals(status) ? "permission_approved" : "permission_rejected";
673→            // Use documentName stored at submit time; fall back to re-query only if null/empty
674→            String documentName = request.getDocumentName();
675→            if (documentName == null || documentName.isBlank()) {
676→                try {
677→                    SpaceNodeEntity node = getSpaceNodeByNodeIdSafe(request.getDocumentId());
678→                    documentName = node != null ? node.getName() : "";
679→                } catch (Exception e) {
680→                    log.debug("[1822-PermApply] notifyApplicantResult get node name failed documentId={}", request.getDocumentId());
681→                    documentName = "";
682→                }
683→            }
684→
685→            Map<String, Object> extras = new HashMap<>();
686→            extras.put("requestId", request.getId());
687→            extras.put("documentId", request.getDocumentId());
688→            extras.put("documentName", documentName);
689→            extras.put("status", status);
690→            extras.put("approverUserId", approverUuid);
691→            extras.put("approverNickName", approverNickName != null ? approverNickName : "");
692→
693→            Map<String, Object> bodyMap = new HashMap<>();
694→            bodyMap.put(BODY_EXTRAS, extras);
695→            String bodyJson = JSONUtil.toJsonStr(bodyMap);
696→
697→            apitableGrpcClientService.createNotification(
698→                templateId,
699→                approverUuid,
700→                Collections.singletonList(String.valueOf(request.getApplicantUserId())),
701→                request.getDocumentId(),
702→                request.getSpaceId(),
703→                bodyJson,
704→                false
705→            );
706→            log.info("[1822-PermApply] notifyApplicantResult requestId={} status={} applicantUserId={}",
707→                request.getId(), status, request.getApplicantUserId());
708→        } catch (Exception e) {
709→            log.error("[1822-PermApply] ERROR notifyApplicantResult requestId={} status={} error={}",
710→                request.getId(), status, e.getMessage(), e);
711→        }
712→    }
713→
714→    private PermissionRequestVo buildVo(PermissionRequestEntity entity, String documentName, String spaceName) {
715→        return PermissionRequestVo.builder()
716→            .id(entity.getId())
717→            .documentId(entity.getDocumentId())
718→            .documentName(documentName)
719→            .spaceId(entity.getSpaceId())
720→            .spaceName(spaceName)
721→            .requestedPermissionType(entity.getRequestedPermissionType())
722→            .status(entity.getStatus())
723→            .createdAt(entity.getCreatedAt())
724→            .build();
725→    }
726→}
