package com.yottastudios.ns.collabspace.space.controller;

import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.space.service.IWorkspaceApplyService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.enums.ParameterIn;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RestController;

/**
 * 空间站成员申请 Controller.
 * 用户在「无空间站权限」页面点击「申请成为该空间站成员」时调用.
 */
@Slf4j
@RestController
@Tag(name = "Workspace")
@ApiResource(path = "/workspaces")
public class WorkspaceApplyController {

    @Resource
    private IWorkspaceApplyService workspaceApplyService;

    @PostResource(path = "/{workspaceId}/applyMembership", requiredPermission = false)
    @Operation(summary = "申请成为空间站成员")
    public ResponseData<Void> applyMembership(
            @Parameter(description = "空间站 ID", required = true, in = ParameterIn.PATH)
            @PathVariable String workspaceId) {
        log.info("[1822-WorkspaceApply] apply entry workspaceId={}", workspaceId);
        workspaceApplyService.applyMembership(workspaceId);
        return ResponseData.success();
    }
}

