package com.yottastudios.ns.collabspace.control.service;

import com.baomidou.mybatisplus.extension.service.IService;
import com.yottastudios.ns.collabspace.control.entity.PermissionRequestEntity;
import com.yottastudios.ns.collabspace.control.ro.DocumentPermissionRequestRo;
import com.yottastudios.ns.collabspace.control.vo.PermissionRequestVo;

import java.util.List;

/**
 * Permission request service interface.
 */
public interface IPermissionRequestService extends IService<PermissionRequestEntity> {


    /**
     * Submit a document permission request.
     *
     * @param documentId document ID (dst prefix)
     * @param ro        request parameters
     * @return permission request VO
     */
    PermissionRequestVo submitRequest(String documentId, DocumentPermissionRequestRo ro);

    /**
     * Get my permission requests.
     *
     * @param userId    user ID
     * @param status    status filter (optional)
     * @param page      page number
     * @param pageSize  page size
     * @return list of permission request VOs
     */
    List<PermissionRequestVo> getMyRequests(Long userId, String status, int page, int pageSize);

    /**
     * Count my permission requests.
     *
     * @param userId   user ID
     * @param status   status filter (optional)
     * @return count
     */
    int countMyRequests(Long userId, String status);

    /**
     * Approve a permission request.
     *
     * @param notificationId   notification ID (apitable player_notification.id)
     * @param approverUserId   approver user ID
     */
    void approve(Long notificationId, Long approverUserId);

    /**
     * Approve by requestId (preferred - caller passes resolved requestId).
     *
     * @param requestId        permission request ID
     * @param notificationId   notification ID (apitable)
     * @param approverUserId   approver user ID
     */
    void approveByRequestId(String requestId, Long notificationId, Long approverUserId);

    /**
     * Reject a permission request.
     *
     * @param notificationId   notification ID
     * @param approverUserId   approver user ID
     */
    void reject(Long notificationId, Long approverUserId);

    /**
     * Reject by requestId (preferred - caller passes resolved requestId).
     *
     * @param requestId        permission request ID
     * @param notificationId   notification ID (apitable)
     * @param approverUserId   approver user ID
     */
    void rejectByRequestId(String requestId, Long notificationId, Long approverUserId);

    /**
     * Ignore - mark notification as read.
     * Validates requestId exists in collabspace permission_request table and approver is admin.
     *
     * @param requestId        permission request ID
     * @param notificationId   notification ID (apitable)
     * @param approverUserId   approver user ID
     */
    void ignoreByRequestId(String requestId, Long notificationId, Long approverUserId);

    /**
     * Reapprove - mark notification as unread so admin can re-handle.
     * Validates requestId exists in collabspace permission_request table and approver is admin.
     * Does NOT require PENDING status (can re-open already-processed requests).
     *
     * @param requestId        permission request ID
     * @param notificationId   notification ID (apitable)
     * @param approverUserId   approver user ID
     */
    void reapproveByRequestId(String requestId, Long notificationId, Long approverUserId);

}

