package com.yottastudios.ns.collabspace.control.enums;

import com.yottastudios.ns.collabspace.core.exception.BaseException;
import lombok.AllArgsConstructor;
import lombok.Getter;

/**
 * Permission request exception.
 * 错误码与 APITable 保持一致：
 * - NotificationException (1201-1299): 通知相关
 * - PermissionException (600-699): 权限相关
 * - SpacePermissionException (601-603): 空间权限相关
 */
@Getter
@AllArgsConstructor
public enum PermissionRequestException implements BaseException {

    // NotificationException (1201-1299) - 与 APITable NotificationException 保持一致
