121→        ExceptionUtil.isFalse(hasPermission, PermissionRequestException.ALREADY_HAVE_PERMISSION);
122→
123→        // 5. Debounce: short period repeated submissions only processed once
124→        String debounceKey = REDIS_DEBOUNCE_PREFIX + applicantUserId + ":" + resolvedDocumentId;
125→        Boolean firstSubmit = redisTemplate.opsForValue().setIfAbsent(debounceKey, "1", DEBOUNCE_SECONDS, TimeUnit.SECONDS);
