171→        List<SpaceNodeEntity> byAppId = spaceNodeService.listByAppSpaceNodeIdsAllStatus(Collections.singletonList(nodeId));
172→        if (CollUtil.isNotEmpty(byAppId)) return byAppId.get(0);
173→        // Fallback: treat as collabspace pk if numeric (non-OnlyOffice node sent its own pk)
174→        if (nodeId.matches("^\\d+$")) {
175→            SpaceNodeEntity node = spaceNodeService.getByIdAllStatus(Long.parseLong(nodeId));
176→            ExceptionUtil.isNotNull(node, PermissionRequestException.NODE_NOT_EXIST);
