233→    @Async
234→    public void notifyAdminsAsync(PermissionRequestEntity request, String documentName,
235→                                   String applicantNickName, String spaceName) {
236→        try {
237→            // Space-level admins (owner + workbench manage permission holders)
238→            List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(request.getSpaceId());
239→
240→            // Document-level MANAGE permission holders (may differ from space admins)
241→            List<Long> docManagerUserIds = getDocumentManagerUserIds(request.getDocumentId(), request.getSpaceId());
242→
243→            // Merge and deduplicate; exclude the applicant (they shouldn't get notified as approver)
244→            Set<Long> toNotifySet = new LinkedHashSet<>();
245→            toNotifySet.addAll(adminUserIds);
246→            toNotifySet.addAll(docManagerUserIds);
247→            toNotifySet.remove(request.getApplicantUserId());
248→            List<Long> allNotifyUserIds = new ArrayList<>(toNotifySet);
249→
250→            if (CollUtil.isEmpty(allNotifyUserIds)) {
251→                log.warn("[1822-PermApply] notifyAdmins no recipients spaceId={} documentId={}",
252→                    request.getSpaceId(), request.getDocumentId());
253→                return;
254→            }
255→            log.info("[1822-PermApply] notifyAdmins requestId={} documentId={} spaceAdminCount={} docManagerCount={} totalNotify={}",
256→                request.getId(), request.getDocumentId(), adminUserIds.size(), docManagerUserIds.size(), allNotifyUserIds.size());
257→
258→            Map<String, Object> extras = new HashMap<>();
259→            extras.put("requestId", request.getId());
260→            extras.put("spaceName", spaceName);
261→            extras.put("applicantUserId", String.valueOf(request.getApplicantUserId()));
262→            extras.put("applicantNickName", applicantNickName);
263→            extras.put("documentId", request.getDocumentId());
264→            extras.put("documentName", documentName);
265→            extras.put("requestedPermissionType", request.getRequestedPermissionType());
266→            extras.put("documentAuth", mapPermissionTypeToLabel(request.getRequestedPermissionType()));
267→            extras.put("status", request.getStatus());
268→
269→            Map<String, Object> bodyMap = new HashMap<>();
270→            bodyMap.put(BODY_EXTRAS, extras);
271→            String bodyJson = JSONUtil.toJsonStr(bodyMap);
272→
273→            apitableGrpcClientService.createNotification(
274→                DOCUMENT_PERMISSION_REQUEST,
275→                String.valueOf(request.getApplicantUserId()),
276→                allNotifyUserIds.stream().map(String::valueOf).collect(Collectors.toList()),
277→                request.getDocumentId(),
278→                request.getSpaceId(),
279→                bodyJson,
280→                true
281→            );
282→
283→            log.info("[1822-PermApply] notifyAdmins done requestId={} totalNotified={}", request.getId(), allNotifyUserIds.size());
284→        } catch (Exception e) {
285→            log.error("[1822-PermApply] ERROR notifyAdmins requestId={} error={}", request.getId(), e.getMessage(), e);
286→        }
287→    }
