370→    @Override
371→    @Transactional(rollbackFor = Exception.class)
372→    public void approveByRequestId(String requestId, Long notificationId, Long approverUserId) {
373→        PermissionRequestEntity request = validateAndGetRequest(requestId, approverUserId);
374→
375→        UserSimpleInfoVo approverInfo = getApproverInfo(approverUserId);
376→        String approverNickName = approverInfo != null && approverInfo.getNickName() != null ? approverInfo.getNickName() : "";
377→        String approverUuid = approverInfo != null && approverInfo.getUuid() != null ? approverInfo.getUuid() : String.valueOf(approverUserId);
378→
379→        // Get applicant unitId
380→        UnitMemberVo applicantMember = apitableGrpcClientService.findUnitMemberVo(
381→                List.of(request.getApplicantUserId()), request.getSpaceId())
382→            .stream().findFirst().orElse(null);
383→        ExceptionUtil.isNotNull(applicantMember, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
384→        Long unitId = applicantMember.getUnitId();
385→        ExceptionUtil.isNotNull(unitId, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
386→
387→        // Map permission type to node role
388→        String nodeRole = mapPermissionTypeToNodeRole(request.getRequestedPermissionType());
389→        log.info("[1822-PermApply] APPROVE mapRole requestId={} requestedType={} nodeRole={} unitId={} documentId={}",
390→            request.getId(), request.getRequestedPermissionType(), nodeRole, unitId, request.getDocumentId());
391→
392→        // Add node role
393→        Long spaceNodeId = parseSpaceNodeId(request.getDocumentId());
394→        if (spaceNodeId != null) {
395→            nodeRoleUpdateManager.addNodeRole(approverUserId, request.getSpaceId(), spaceNodeId, nodeRole,
396→                Collections.singletonList(unitId));
397→            log.info("[1822-PermApply] APPROVE addNodeRole ok spaceNodeId={} nodeRole={} unitId={}", spaceNodeId, nodeRole, unitId);
398→        } else {
399→            log.warn("[1822-PermApply] APPROVE WARN spaceNodeId not found for documentId={}, node permission grant SKIPPED",
400→                request.getDocumentId());
401→        }
402→
403→        // Update permission request status in collabspace
404→        int rows = baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);
405→        log.info("[1822-PermApply] APPROVE DB updateStatus requestId={} status=APPROVED approverUserId={} rows={}",
406→            request.getId(), approverUserId, rows);
407→
408→        // Update notification extras in apitable (via gRPC) — updates shared notification record for all recipients
409→        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_APPROVED,
410→            approverUuid, approverNickName);
411→
412→        // Mark approver's own notification as read
413→        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);
414→
415→        // Mark all other admin/manager recipients' notifications as read (same shared notificationId)
416→        markOtherRecipientNotificationsRead(notificationId, request, approverUserId);
417→
418→        // Notify applicant that their request was approved
419→        notifyApplicantResultAsync(request, STATUS_APPROVED, approverUuid, approverNickName);
420→
421→        log.info("[1822-PermApply] APPROVE done requestId={} approverUserId={} applicantUserId={} documentId={} nodeRole={}",
422→            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId(), nodeRole);
423→    }
