657→    /**
658→     * Returns the collabspace userIds of all users who have explicit MANAGE permission on the document.
659→     * Handles both member-type (individual) and team-type (department) unit entries in control_role.
660→     */
661→    private List<Long> getDocumentManagerUserIds(String documentId, String spaceId) {
662→        try {
663→            Long spaceNodeId = parseSpaceNodeId(documentId);
664→            if (spaceNodeId == null) return List.of();
665→
666→            List<ControlRoleEntity> roles = controlRoleService.getByControlId(spaceNodeId.toString());
667→            List<Long> managerUnitIds = roles.stream()
668→                .filter(r -> MANAGER.equals(r.getRoleCode()))
669→                .map(ControlRoleEntity::getUnitId)
670→                .toList();
671→
672→            if (CollUtil.isEmpty(managerUnitIds)) return List.of();
673→
674→            List<NodeRoleUnit> nodeRoleUnits = apitableGrpcClientService.getNodeRoleUnitList(spaceId, managerUnitIds);
675→
676→            Set<Long> userIds = new HashSet<>();
677→            List<Long> memberTypeRefIds = new ArrayList<>(); // memberId for unitType=3
678→
679→            for (NodeRoleUnit unit : nodeRoleUnits) {
680→                if (unit.getUnitRefId() == null) continue;
681→                Integer unitType = unit.getUnitType();
682→                if (unitType != null && unitType == 1) {
683→                    // Team/department: expand to all members
684→                    List<UserSimpleInfoVo> members = apitableGrpcClientService.selectMembersByTeamId(spaceId, unit.getUnitRefId());
685→                    members.stream().filter(m -> m.getId() != null).forEach(m -> userIds.add(m.getId()));
686→                } else if (unitType != null && unitType == 3) {
687→                    // Individual member: collect memberId for batch email lookup
688→                    memberTypeRefIds.add(unit.getUnitRefId());
689→                }
690→            }
691→
692→            // Resolve member-type units: memberId → email → userId
693→            if (!memberTypeRefIds.isEmpty()) {
694→                IPage<SpaceMemberVo> memberPage = apitableGrpcClientService.getSpaceMembers(spaceId, 1, 999);
695→                Map<String, String> memberIdToEmail = memberPage.getRecords().stream()
696→                    .filter(m -> m.getMemberId() != null && m.getEmail() != null)
697→                    .collect(Collectors.toMap(SpaceMemberVo::getMemberId, SpaceMemberVo::getEmail, (a, b) -> a));
698→
699→                List<String> emails = memberTypeRefIds.stream()
700→                    .map(refId -> memberIdToEmail.get(String.valueOf(refId)))
701→                    .filter(Objects::nonNull)
702→                    .toList();
703→
704→                if (!emails.isEmpty()) {
705→                    apitableGrpcClientService.getUserByEmails(emails).stream()
706→                        .filter(u -> u.getId() != null)
707→                        .forEach(u -> userIds.add(u.getId()));
708→                }
709→            }
710→
711→            log.info("[1822-PermApply] getDocumentManagerUserIds documentId={} managerUnitCount={} resolvedUserCount={}",
712→                documentId, managerUnitIds.size(), userIds.size());
713→            return new ArrayList<>(userIds);
714→        } catch (Exception e) {
715→            log.warn("[1822-PermApply] getDocumentManagerUserIds failed documentId={} error={}", documentId, e.getMessage());
716→            return List.of();
717→        }
718→    }
