  adminEmail: 'test224@yottastudios.com',
  // 普通成员（已在空间站，用于测试"已是成员"拦截）
  memberEmail: 'test222@yottastudios.com',
  // 申请人（不在 spcU5JzydCyse 空间站的用户）
  applicantEmail: 'test1@yottastudios.com',
  // 另一个不在空间站的用户（备用申请人）
  applicant2Email: 'tt2@yottastudios.com',
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';
let xsrfToken = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========

function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const [k, v] = kv.split('=');
    if (k && v) cookies[k.trim()] = v.trim();
  }
  return cookies;
}

async function rawFetch(method, url, body) {
  const headers = {
    'content-type': 'application/json',
  };
  if (cookie) headers['cookie'] = cookie;
  if (xsrfToken) headers['x-xsrf-token'] = xsrfToken;

  const opts = { method, headers, redirect: 'manual' };
  if (body !== undefined) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}${CONFIG.apiPrefix}${path}`);
  return res.json();
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}${CONFIG.apiPrefix}${path}`, body);
  const text = await res.text();
  try {
    return JSON.parse(text);
  } catch {
    return { success: false, code: res.status, message: text.slice(0, 200) };
  }
}

async function POST_RAW(path, body) {
  return rawFetch('POST', `${CONFIG.host}${CONFIG.apiPrefix}${path}`, body);
}

// ========== 登录管理 ==========

async function login(email) {
  console.log(`🔑 登录 ${email} ...`);
  const res = await fetch(`${CONFIG.host}${CONFIG.apiPrefix}/auth/testLogin/${email}`, { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log('  ⚠️ 登录失败（无 SESSION cookie）');
    return false;
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  console.log(`  ✅ 登录成功\n`);
  return true;
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = { cookie, xsrfToken };
}
function restoreSession(name) {
  ({ cookie, xsrfToken } = savedSessions[name]);
}
function clearSession() {
  cookie = '';
  xsrfToken = '';
}

// ========== 测试用例 ==========

// §1. 用户申请加入空间站
async function test_1_apply_membership() {
  console.log('\n📋 §1. 用户申请加入空间站');

  // §1.1 正常申请 — 用不在空间站的用户
  restoreSession('applicant');
  const res = await POST(`/workspaces/${CONFIG.workspaceId}/applyMembership`);
  assert('§1.申请加入 - 接口返回 success', res.success === true, res);
  assert('§1.申请加入 - code=200', res.code === 200, res.code);

  // §1.2 已是成员拦截 — 用已在空间站的成员
  restoreSession('member');
  const res2 = await POST(`/workspaces/${CONFIG.workspaceId}/applyMembership`);
  assert('§1.已是成员 - 返回 success=false', res2.success === false, res2);
  assert('§1.已是成员 - 不返回500', res2.code !== 500, res2.code);

  // §1.3 Redis 防重复 — 同一用户再次申请（1小时内）
  restoreSession('applicant');
  const res3 = await POST(`/workspaces/${CONFIG.workspaceId}/applyMembership`);
  assert('§1.防重复 - 1小时内重复申请被拦截', res3.success === false, res3);
  assert('§1.防重复 - 不返回500', res3.code !== 500, res3.code);
}

// §2. 通知中心展示
async function test_2_notification_display() {
  console.log('\n📋 §2. 通知中心展示（通知由 apitable gRPC 管理，此处验证通知已创建）');

  // 通知是通过 gRPC 发到 apitable 的，我们无法直接通过 collabspace API 查询
  // 这里只验证申请记录已入库
  restoreSession('admin');

  // 查 DB 验证：通过后续审批接口间接验证通知存在
  console.log('  ℹ️  通知内容通过 apitable gRPC 发送，需在 apitable 通知中心手动验证');
  console.log('  ℹ️  验证点：extras 含 type=WORKSPACE, applicantNickName, documentName(空间站名称)');
  assert('§2.通知 - 跳过（gRPC 通知需手动验证）', true);
}

// §3. 审批操作 — approve
async function test_3_approve() {
  console.log('\n📋 §3. 审批操作 - 同意');

  // 需要先有一条 PENDING 的 workspace 申请记录
  // 用 applicant2 发起新申请
  restoreSession('applicant2');
  const applyRes = await POST(`/workspaces/${CONFIG.workspaceId}/applyMembership`);
  if (!applyRes.success) {
    console.log(`  ⚠️ applicant2 申请失败（可能 Redis 冷却中），跳过 approve 测试`);
    console.log(`     结果: ${JSON.stringify(applyRes).slice(0, 200)}`);
    assert('§3.同意 - 跳过（无法创建测试申请）', false, applyRes);
    return;
  }

  // 由于 approve 需要 notificationId，而通知在 apitable 侧
  // 我们无法直接拿到 notificationId，需要通过 apitable 查询
  console.log('  ℹ️  approve/reject/ignore/reapprove 需要 notificationId（来自 apitable 通知中心）');
  console.log('  ℹ️  自动化测试无法获取 notificationId，以下用假 ID 测试异常处理');

  // 用假 notificationId 测试错误处理
  restoreSession('admin');
  const fakeNotificationId = '1';
  const res = await POST(`/player/notification/${fakeNotificationId}/approve`);
  assert('§3.同意 - 假 notificationId 返回 success=false', res.success === false, res);
  assert('§3.同意 - 假 notificationId 不返回500', res.code !== 500, res.code);
}

// §4. 审批操作 — reject
async function test_4_reject() {
  console.log('\n📋 §4. 审批操作 - 拒绝');

  restoreSession('admin');
  const fakeNotificationId = '1';
  const res = await POST(`/player/notification/${fakeNotificationId}/reject`);
  assert('§4.拒绝 - 假 notificationId 返回 success=false', res.success === false, res);
  assert('§4.拒绝 - 假 notificationId 不返回500', res.code !== 500, res.code);
}

// §5. 审批操作 — ignore
async function test_5_ignore() {
  console.log('\n📋 §5. 审批操作 - 忽略');

  restoreSession('admin');
  const fakeNotificationId = '1';
  const res = await POST(`/player/notification/${fakeNotificationId}/ignore`);
  assert('§5.忽略 - 假 notificationId 返回 success=false', res.success === false, res);
  assert('§5.忽略 - 假 notificationId 不返回500', res.code !== 500, res.code);
}

// §6. 审批操作 — reapprove
async function test_6_reapprove() {
  console.log('\n📋 §6. 审批操作 - 重新审批');

  restoreSession('admin');
  const fakeNotificationId = '1';
  const res = await POST(`/player/notification/${fakeNotificationId}/reapprove`);
  assert('§6.重新审批 - 假 notificationId 返回 success=false', res.success === false, res);
  assert('§6.重新审批 - 假 notificationId 不返回500', res.code !== 500, res.code);
}

// §7. 审批人校验 — 非管理员不能审批
async function test_7_approver_permission() {
  console.log('\n📋 §7. 审批人校验 - 非管理员不能审批');

  // 用普通成员尝试审批
  restoreSession('member');
  const fakeNotificationId = '1';

  const res1 = await POST(`/player/notification/${fakeNotificationId}/approve`);
  assert('§7.权限 - 普通成员 approve 返回 success=false', res1.success === false, res1);
  assert('§7.权限 - 普通成员 approve 不返回500', res1.code !== 500, res1.code);

  const res2 = await POST(`/player/notification/${fakeNotificationId}/reject`);
  assert('§7.权限 - 普通成员 reject 返回 success=false', res2.success === false, res2);
  assert('§7.权限 - 普通成员 reject 不返回500', res2.code !== 500, res2.code);
}

// §8. 参数校验
async function test_8_param_validation() {
  console.log('\n📋 §8. 参数校验');

  restoreSession('applicant');

  // 空 workspaceId
  const res1 = await POST('/workspaces//applyMembership');
  assert('§8.参数 - 空 workspaceId 不返回500',
    res1.code !== 500 || res1.success === false, res1);

  // 不存在的 workspaceId
  const res2 = await POST('/workspaces/spc_not_exist_12345/applyMembership');
  assert('§8.参数 - 不存在 workspaceId 返回 success=false', res2.success === false, res2);
  assert('§8.参数 - 不存在 workspaceId 不返回500', res2.code !== 500, res2.code);
}

// §9. 注入防护 + 特殊字符
async function test_9_injection() {
  console.log('\n📋 §9. 注入防护 + 特殊字符');

  restoreSession('applicant');

  const injections = [
    "' OR 1=1 --",
    "1; DROP TABLE collabspace_permission_request;",
    "<script>alert(1)</script>",
    "spc' UNION SELECT * FROM collabspace_user --",
  ];

  for (const payload of injections) {
    const encodedPayload = encodeURIComponent(payload);
    const res = await POST(`/workspaces/${encodedPayload}/applyMembership`);
    assert(`§9.注入 - "${payload.slice(0, 30)}..." 不返回500`,
      res.code !== 500 || res.success !== undefined, res);
  }

  // notificationId 注入测试
  restoreSession('admin');
  const notifInjections = ['abc', '0', '-1'];
  for (const payload of notifInjections) {
    const res = await POST(`/player/notification/${payload}/approve`);
    assert(`§9.注入 - notificationId="${payload}" 不返回500`,
      res.code !== 500 || res.success !== undefined, res);
  }
}

// §10. 未登录访问
async function test_10_unauthenticated() {
  console.log('\n📋 §10. 未登录访问');

  saveSession('admin');
  clearSession();

  // POST 写操作必须被拒绝
  const res1 = await POST_RAW(`/workspaces/${CONFIG.workspaceId}/applyMembership`);
  assert('§10.未登录 - applyMembership 返回非200', res1.status !== 200, res1.status);

  const res2 = await POST_RAW('/player/notification/1/approve');
  assert('§10.未登录 - approve 返回非200', res2.status !== 200, res2.status);

  const res3 = await POST_RAW('/player/notification/1/reject');
  assert('§10.未登录 - reject 返回非200', res3.status !== 200, res3.status);

  const res4 = await POST_RAW('/player/notification/1/ignore');
  assert('§10.未登录 - ignore 返回非200', res4.status !== 200, res4.status);

  const res5 = await POST_RAW('/player/notification/1/reapprove');
  assert('§10.未登录 - reapprove 返回非200', res5.status !== 200, res5.status);

  restoreSession('admin');
}

// §11. 并发请求
async function test_11_concurrency() {
  console.log('\n📋 §11. 并发请求');

  restoreSession('admin');

  // 5 个并发 approve 请求（都用假 notificationId，验证不崩溃）
  const promises = Array.from({ length: 5 }, (_, i) =>
    POST(`/player/notification/${i + 100}/approve`)
  );
  const results = await Promise.all(promises);
  const noCrash = results.every(r => r.code !== 500);
  assert('§11.并发 - 5 个并发 approve 都不返回500', noCrash, results.map(r => r.code));
}

// §12. 错误码规范性
async function test_12_error_codes() {
  console.log('\n📋 §12. 错误码规范性');

  // 已是成员
  restoreSession('member');
  const res1 = await POST(`/workspaces/${CONFIG.workspaceId}/applyMembership`);
  assert('§12.错误码 - 已是成员 success=false', res1.success === false, res1);
  assert('§12.错误码 - 已是成员 code 非500', res1.code !== 500, res1.code);

  // 非管理员审批
  const res2 = await POST('/player/notification/1/approve');
  assert('§12.错误码 - 非管理员审批 success=false', res2.success === false, res2);
  assert('§12.错误码 - 非管理员审批 code 非500', res2.code !== 500, res2.code);

  // 不存在的空间站
  restoreSession('applicant');
  const res3 = await POST('/workspaces/spc_fake_xyz/applyMembership');
  assert('§12.错误码 - 不存在空间站 success=false', res3.success === false, res3);
  assert('§12.错误码 - 不存在空间站 code 非500', res3.code !== 500, res3.code);
}

// ========== 数据清理 ==========
async function cleanup() {
  console.log('\n🧹 数据清理');
  // 本次测试创建的 permission_request 记录需要清理
  // 由于只有 DB 操作权限（无 DELETE API），标记为需手动清理
  console.log('  ℹ️  测试产生的 PENDING 状态申请记录需在 Redis 过期（1小时）后自动失效');
  console.log('  ℹ️  DB 中的 permission_request 记录不影响业务（PENDING 状态会被防重复逻辑拦截）');
  console.log('  ℹ️  如需清理 Redis 冷却 key，pattern: workspace_apply:{userId}:{workspaceId}');
}

// ========== 执行 ==========
async function main() {
  console.log('🚀 空间站权限审批优化 - 接口测试');
  console.log(`   目标: ${CONFIG.host}`);
  console.log('');
  console.log('📋 功能点覆盖清单（来自功能点对照文档）：');
  console.log('  §1. 用户申请加入空间站（applyMembership + 已是成员拦截 + Redis防重复）');
  console.log('  §2. 通知中心展示（gRPC 通知，需手动验证）');
  console.log('  §3. 审批操作 - 同意（approve + 自动加入空间站）');
  console.log('  §4. 审批操作 - 拒绝（reject）');
  console.log('  §5. 审批操作 - 忽略（ignore，标记已读）');
  console.log('  §6. 审批操作 - 重新审批（reapprove，标记未读）');
  console.log('  §7. 审批人校验（仅空间站管理员可审批）');
  console.log('  §8. 参数校验');
  console.log('  §9. 注入防护');
  console.log('  §10. 未登录访问');
  console.log('  §11. 并发请求');
  console.log('  §12. 错误码规范性');
  console.log('');

  try {
    // 登录所有测试账号
    if (!await login(CONFIG.adminEmail)) {
      console.log('❌ 管理员登录失败，终止测试');
      process.exit(1);
    }
    saveSession('admin');

    if (!await login(CONFIG.memberEmail)) {
      console.log('❌ 成员登录失败，终止测试');
      process.exit(1);
    }
    saveSession('member');

    if (!await login(CONFIG.applicantEmail)) {
      console.log('❌ 申请人登录失败，终止测试');
      process.exit(1);
    }
    saveSession('applicant');

    if (!await login(CONFIG.applicant2Email)) {
      console.log('❌ 申请人2登录失败，终止测试');
      process.exit(1);
    }
    saveSession('applicant2');

    restoreSession('admin');

    // 按功能点顺序执行
    await test_1_apply_membership();
    await test_2_notification_display();
    await test_3_approve();
    await test_4_reject();
    await test_5_ignore();
    await test_6_reapprove();
    await test_7_approver_permission();
    await test_8_param_validation();
    await test_9_injection();
    await test_10_unauthenticated();
    await test_11_concurrency();
    await test_12_error_codes();

    await cleanup();
  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接测试环境，请检查网络');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    process.exit(1);
  }

  console.log(`\n=============================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`=============================`);
  process.exit(failed > 0 ? 1 : 0);
}
main();

