213→+    @Override
214→+    @Transactional(rollbackFor = Exception.class)
215→+    public void submitWorkspaceJoinRequest(String workspaceId, Long applicantUserId) {
216→+        ExceptionUtil.isNotNull(workspaceId, PermissionRequestException.NODE_NOT_EXIST);
217→+        ExceptionUtil.isNotNull(applicantUserId, PermissionRequestException.NODE_ACCESS_DENIED);
218→+
219→+        // 1. Check no pending workspace request
220→+        PermissionRequestEntity pending = baseMapper.selectPendingWorkspaceBySpaceAndApplicant(workspaceId, applicantUserId);
221→+        ExceptionUtil.isNull(pending, PermissionRequestException.ALREADY_SUBMITTED_WORKSPACE_REQUEST);
222→+
223→+        // 2. Get applicant nickname and space name
224→+        String applicantNickName = getApplicantNickName(applicantUserId);
225→+        SpaceEntity space = spaceService.getBySpaceId(workspaceId);
226→+        String spaceName = space != null && space.getName() != null ? space.getName() : workspaceId;
227→+
228→+        // 3. Create permission request record
229→+        String requestId = REQUEST_ID_PREFIX + IdUtil.getSnowflakeNextId();
230→+        PermissionRequestEntity entity = PermissionRequestEntity.builder()
231→+            .id(requestId)
232→+            .type(TYPE_WORKSPACE)
233→+            .applicantUserId(applicantUserId)
234→+            .documentId(workspaceId)
235→+            .documentName(spaceName)
236→+            .spaceId(workspaceId)
237→+            .requestedPermissionType(null)
238→+            .status(STATUS_PENDING)
239→+            .isDeleted(0)
240→+            .createdAt(LocalDateTime.now())
241→+            .updatedAt(LocalDateTime.now())
242→+            .build();
243→+
244→+        boolean flag = save(entity);
245→+        if (!flag) {
246→+            log.error("[2423-WorkspaceJoin] ERROR CREATE insert failed applicantUserId={} workspaceId={}",
247→+                applicantUserId, workspaceId);
248→+            throw new BusinessException(PermissionRequestException.INSERT_ERROR);
249→+        }
250→+        log.info("[2423-WorkspaceJoin] CREATE request requestId={} applicantUserId={} workspaceId={}",
251→+            requestId, applicantUserId, workspaceId);
252→+
253→+        // 4. Get space admins as notification recipients
254→+        List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(workspaceId);
255→+        if (CollUtil.isEmpty(adminUserIds)) {
256→+            log.warn("[2423-WorkspaceJoin] no admins workspaceId={}", workspaceId);
257→+            return;
258→+        }
259→+        // Exclude applicant from recipients
260→+        adminUserIds = new ArrayList<>(adminUserIds);
261→+        adminUserIds.remove(applicantUserId);
262→+        if (CollUtil.isEmpty(adminUserIds)) {
263→+            log.warn("[2423-WorkspaceJoin] applicant is the only admin workspaceId={}", workspaceId);
264→+            return;
265→+        }
266→+
267→+        // 5. Send notification via apitable notification center
268→+        notifyWorkspaceAdminsAsync(entity, spaceName, applicantNickName, adminUserIds);
269→+    }
