import java.util.concurrent.TimeUnit;
import java.util.stream.Collectors;

import static com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants.Node.EDITOR;
import static com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants.Node.MANAGER;
import static com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants.Node.READER;

/**
 * Permission request service implementation.
 * Full implementation migrated from apitable-backend-server.
 * All notifications are sent to apitable via gRPC.
 */
@Slf4j
@Service
public class PermissionRequestServiceImpl extends ServiceImpl<PermissionRequestMapper, PermissionRequestEntity>
    implements IPermissionRequestService {

    private static final String STATUS_PENDING = "PENDING";
    private static final String STATUS_APPROVED = "APPROVED";
    private static final String STATUS_REJECTED = "REJECTED";
    private static final String REQUEST_ID_PREFIX = "req_";

    private static final String REDIS_DEBOUNCE_PREFIX = "permission_apply_debounce:";
    private static final long DEBOUNCE_SECONDS = 10;

    private static final String DOCUMENT_PERMISSION_REQUEST = "document_permission_request";
    private static final String BODY_EXTRAS = "extras";

    private static final String TYPE_DOCUMENT = "DOCUMENT";
    private static final String TYPE_WORKSPACE = "WORKSPACE";

    @Resource
    private IControlService controlService;

    @Resource
    private ISpaceService spaceService;

    @Resource
    private ISpaceNodeService spaceNodeService;

    @Resource
    private SpaceQueryManager spaceQueryManager;

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Resource
    private RedisTemplate<String, Object> redisTemplate;

    @Resource
    private NodeRoleUpdateManager nodeRoleUpdateManager;

    @Resource
    private NodeRoleQueryManager nodeRoleQueryManager;

    @Resource
    private IControlRoleService controlRoleService;

    // ========== submitRequest ==========

    @Override
    @Transactional(rollbackFor = Exception.class)
    public PermissionRequestVo submitRequest(String documentId, DocumentPermissionRequestRo ro) {
        Long applicantUserId = SessionContext.getUserId();
        ExceptionUtil.isNotNull(applicantUserId, PermissionRequestException.NODE_ACCESS_DENIED);
        ExceptionUtil.isNotNull(documentId, PermissionRequestException.NODE_NOT_EXIST);

        // 1. Check node exists and get spaceId; resolve numeric pk to appSpaceNodeId
        SpaceNodeEntity spaceNode = getSpaceNodeByNodeId(documentId);
        String resolvedDocumentId = spaceNode.getAppSpaceNodeId();
        String spaceId = spaceNode.getSpaceId();
        String documentName = spaceNode.getName();

        // 2. Check user is in space
        boolean isInSpace = spaceQueryManager.isUserInSpace(applicantUserId, spaceId);
        ExceptionUtil.isTrue(isInSpace, PermissionRequestException.MEMBER_NOT_IN_SPACE);

        // 3. Check no pending request for same document
        PermissionRequestEntity pending = baseMapper.selectPendingByDocumentAndApplicant(resolvedDocumentId, applicantUserId);
        ExceptionUtil.isNull(pending, PermissionRequestException.ALREADY_SUBMITTED_REQUEST);

        // 4. Check user does not already have node permission
        boolean hasPermission = checkUserHasNodePermission(spaceId, applicantUserId, resolvedDocumentId);
        ExceptionUtil.isFalse(hasPermission, PermissionRequestException.ALREADY_HAVE_PERMISSION);

        // 5. Debounce: short period repeated submissions only processed once
        String debounceKey = REDIS_DEBOUNCE_PREFIX + applicantUserId + ":" + resolvedDocumentId;
        Boolean firstSubmit = redisTemplate.opsForValue().setIfAbsent(debounceKey, "1", DEBOUNCE_SECONDS, TimeUnit.SECONDS);
        if (Boolean.FALSE.equals(firstSubmit)) {
            log.info("[1822-PermApply] debounce applicantUserId={} documentId={}", applicantUserId, documentId);
            throw new BusinessException(PermissionRequestException.ALREADY_SUBMITTED_REQUEST);
        }

        // 6. Create permission request record
        String requestId = REQUEST_ID_PREFIX + IdUtil.getSnowflakeNextId();
        PermissionRequestEntity entity = PermissionRequestEntity.builder()
            .id(requestId)
            .applicantUserId(applicantUserId)
            .documentId(resolvedDocumentId)
            .documentName(documentName)
            .spaceId(spaceId)
            .requestedPermissionType(ro.getRequestedPermissionType())
            .status(STATUS_PENDING)
            .isDeleted(0)
            .createdAt(LocalDateTime.now())
            .updatedAt(LocalDateTime.now())
            .build();

        boolean flag = save(entity);
        if (!flag) {
            log.error("[1822-PermApply] ERROR CREATE insert failed applicantUserId={} documentId={} spaceId={}",
                applicantUserId, resolvedDocumentId, spaceId);
            throw new BusinessException(PermissionRequestException.INSERT_ERROR);
        }
        log.info("[1822-PermApply] CREATE request requestId={} applicantUserId={} documentId={} spaceId={} requestedType={}",
            requestId, applicantUserId, resolvedDocumentId, spaceId, ro.getRequestedPermissionType());

        // 7. Get space name and applicant nickname
        SpaceEntity space = spaceService.getBySpaceId(spaceId);
        String spaceName = space != null && space.getName() != null ? space.getName() : "";
        String applicantNickName = getApplicantNickName(applicantUserId);

        // 8. Notify admins & applicant via apitable gRPC (async)
        notifyAdminsAsync(entity, documentName, applicantNickName, spaceName);
        notifyApplicantAsync(entity, documentName, spaceName);

        return buildVo(entity, documentName, spaceName);
    }

    private SpaceNodeEntity getSpaceNodeByNodeId(String nodeId) {
        ExceptionUtil.isNotNull(nodeId, PermissionRequestException.NODE_NOT_EXIST);
        // Always try appSpaceNodeId first (including deleted rows): OnlyOffice nodes use a numeric
        // fileId as appSpaceNodeId, which must NOT be treated as the collabspace pk.
        List<SpaceNodeEntity> byAppId = spaceNodeService.listByAppSpaceNodeIdsAllStatus(Collections.singletonList(nodeId));
        if (CollUtil.isNotEmpty(byAppId)) return byAppId.get(0);
        // Fallback: treat as collabspace pk if numeric (non-OnlyOffice node sent its own pk)
        if (nodeId.matches("^\\d+$")) {
            SpaceNodeEntity node = spaceNodeService.getByIdAllStatus(Long.parseLong(nodeId));
            ExceptionUtil.isNotNull(node, PermissionRequestException.NODE_NOT_EXIST);
            return node;
        }
        ExceptionUtil.isNotNull(null, PermissionRequestException.NODE_NOT_EXIST);
        return null; // unreachable
    }

    private SpaceNodeEntity getSpaceNodeByNodeIdSafe(String nodeId) {
        if (nodeId == null) return null;
        // Always try by appSpaceNodeId column first (including deleted rows).
        List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIdsAllStatus(Collections.singletonList(nodeId));
        if (CollUtil.isNotEmpty(nodes)) return nodes.get(0);
        // Fallback: treat as pk if numeric — only reached for non-OnlyOffice nodes.
        if (nodeId.matches("^\\d+$")) {
            return spaceNodeService.getByIdAllStatus(Long.parseLong(nodeId));
        }
        return null;
    }

    /**
     * Check if user has at least READ permission on the node.
     */
    private boolean checkUserHasNodePermission(String spaceId, Long userId, String documentId) {
        try {
            boolean exists = controlService.existsByControlId(documentId);
            if (!exists) {
                return false;
            }
            UnitMemberVo memberVo = apitableGrpcClientService.findUnitMemberVo(List.of(userId), spaceId)
                .stream().findFirst().orElse(null);
            if (memberVo == null || memberVo.getUnitId() == null) {
                return false;
            }
            List<ControlRoleEntity> roles = controlRoleService.getByControlIdAndUnitIds(
                documentId, Collections.singletonList(memberVo.getUnitId()));
            return CollUtil.isNotEmpty(roles);
        } catch (Exception e) {
            log.debug("[1822-PermApply] checkUserHasNodePermission error userId={} documentId={}", userId, documentId);
            return false;
        }
    }

    private String getApplicantNickName(Long userId) {
        try {
            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
            if (user != null && user.getNickName() != null) {
                return user.getNickName();
            }
            return "用户" + userId;
        } catch (Exception e) {
            log.warn("[1822-PermApply] getApplicantNickName error userId={}", userId, e);
            return "用户" + userId;
        }
    }

    // ========== Notification via gRPC ==========

    @Async
    public void notifyAdminsAsync(PermissionRequestEntity request, String documentName,
                                   String applicantNickName, String spaceName) {
        try {
            // Space-level admins (owner + workbench manage permission holders)
            List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(request.getSpaceId());

            // Document-level MANAGE permission holders (may differ from space admins)
            List<Long> docManagerUserIds = getDocumentManagerUserIds(request.getDocumentId(), request.getSpaceId());

            // Merge and deduplicate; exclude the applicant (they shouldn't get notified as approver)
            Set<Long> toNotifySet = new LinkedHashSet<>();
            toNotifySet.addAll(adminUserIds);
            toNotifySet.addAll(docManagerUserIds);
            toNotifySet.remove(request.getApplicantUserId());
            List<Long> allNotifyUserIds = new ArrayList<>(toNotifySet);

            if (CollUtil.isEmpty(allNotifyUserIds)) {
                log.warn("[1822-PermApply] notifyAdmins no recipients spaceId={} documentId={}",
                    request.getSpaceId(), request.getDocumentId());
                return;
            }
            log.info("[1822-PermApply] notifyAdmins requestId={} documentId={} spaceAdminCount={} docManagerCount={} totalNotify={}",
                request.getId(), request.getDocumentId(), adminUserIds.size(), docManagerUserIds.size(), allNotifyUserIds.size());

            Map<String, Object> extras = new HashMap<>();
            extras.put("requestId", request.getId());
            extras.put("spaceName", spaceName);
            extras.put("applicantUserId", String.valueOf(request.getApplicantUserId()));
            extras.put("applicantNickName", applicantNickName);
            extras.put("documentId", request.getDocumentId());
            extras.put("documentName", documentName);
            extras.put("requestedPermissionType", request.getRequestedPermissionType());
            extras.put("documentAuth", mapPermissionTypeToLabel(request.getRequestedPermissionType()));
            extras.put("status", request.getStatus());

            Map<String, Object> bodyMap = new HashMap<>();
            bodyMap.put(BODY_EXTRAS, extras);
            String bodyJson = JSONUtil.toJsonStr(bodyMap);

            apitableGrpcClientService.createNotification(
                DOCUMENT_PERMISSION_REQUEST,
                String.valueOf(request.getApplicantUserId()),
                allNotifyUserIds.stream().map(String::valueOf).collect(Collectors.toList()),
                request.getDocumentId(),
                request.getSpaceId(),
                bodyJson,
                true
            );

            log.info("[1822-PermApply] notifyAdmins done requestId={} totalNotified={}", request.getId(), allNotifyUserIds.size());
        } catch (Exception e) {
            log.error("[1822-PermApply] ERROR notifyAdmins requestId={} error={}", request.getId(), e.getMessage(), e);
        }
    }

