    // ========== Approve / Reject / Ignore / Reapprove (workspace) ==========

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void approveWorkspaceByRequestId(String requestId, Long notificationId, Long approverUserId) {
        PermissionRequestEntity request = validateAndGetWorkspaceRequest(requestId, approverUserId);

        UserSimpleInfoVo approverInfo = getApproverInfo(approverUserId);
        String approverNickName = approverInfo != null && approverInfo.getNickName() != null ? approverInfo.getNickName() : "";
        String approverUuid = approverInfo != null && approverInfo.getUuid() != null ? approverInfo.getUuid() : String.valueOf(approverUserId);

        // Add applicant to space root team (teamId=0L)
        String workspaceId = request.getSpaceId();
        try {
            apitableGrpcClientService.addUsersToTeam(workspaceId,
                List.of(request.getApplicantUserId()), 0L, true);
            log.info("[lbl][2423-空间站审批][WorkspaceJoin] APPROVE addUsersToTeam ok workspaceId={} applicantUserId={}",
                workspaceId, request.getApplicantUserId());
        } catch (Exception e) {
            log.error("[lbl][2423-空间站审批][WorkspaceJoin] APPROVE addUsersToTeam FAILED workspaceId={} applicantUserId={} error={}",
                workspaceId, request.getApplicantUserId(), e.getMessage(), e);
            throw new BusinessException("加入空间站失败: " + e.getMessage());
        }

        // Update request status
        int rows = baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);
        log.info("[lbl][2423-空间站审批][WorkspaceJoin] APPROVE DB updateStatus requestId={} rows={}", request.getId(), rows);

        // Update notification extras + mark read
        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_APPROVED,
            approverUuid, approverNickName);
        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);

        // Mark other admins' notifications as read
        markOtherWorkspaceRecipientNotificationsRead(notificationId, request, approverUserId);

        // Notify applicant
        notifyWorkspaceApplicantResultAsync(request, STATUS_APPROVED, approverUuid, approverNickName);

        log.info("[lbl][2423-空间站审批][WorkspaceJoin] APPROVE done requestId={} approverUserId={} applicantUserId={} workspaceId={}",
            request.getId(), approverUserId, request.getApplicantUserId(), workspaceId);
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void rejectWorkspaceByRequestId(String requestId, Long notificationId, Long approverUserId) {
        PermissionRequestEntity request = validateAndGetWorkspaceRequest(requestId, approverUserId);

        UserSimpleInfoVo approverInfo = getApproverInfo(approverUserId);
        String approverNickName = approverInfo != null && approverInfo.getNickName() != null ? approverInfo.getNickName() : "";
        String approverUuid = approverInfo != null && approverInfo.getUuid() != null ? approverInfo.getUuid() : String.valueOf(approverUserId);

        // Update request status
        int rows = baseMapper.updateStatusById(request.getId(), STATUS_REJECTED, approverUserId);
        log.info("[lbl][2423-空间站审批][WorkspaceJoin] REJECT DB updateStatus requestId={} rows={}", request.getId(), rows);

        // Update notification extras + mark read
        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_REJECTED,
            approverUuid, approverNickName);
        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);

        // Mark other admins' notifications as read
        markOtherWorkspaceRecipientNotificationsRead(notificationId, request, approverUserId);

        // Notify applicant
        notifyWorkspaceApplicantResultAsync(request, STATUS_REJECTED, approverUuid, approverNickName);

        log.info("[lbl][2423-空间站审批][WorkspaceJoin] REJECT done requestId={} approverUserId={} applicantUserId={}",
            request.getId(), approverUserId, request.getApplicantUserId());
    }

    @Override
    public void ignoreWorkspaceByRequestId(String requestId, Long notificationId, Long approverUserId) {
        validateWorkspaceRequestForApprover(requestId, approverUserId);
        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);
        log.info("[lbl][2423-空间站审批][WorkspaceJoin] IGNORE requestId={} notificationId={} approverUserId={}",
            requestId, notificationId, approverUserId);
    }

    @Override
    public void reapproveWorkspaceByRequestId(String requestId, Long notificationId, Long approverUserId) {
        validateWorkspaceRequestForApprover(requestId, approverUserId);
        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, false);
        log.info("[lbl][2423-空间站审批][WorkspaceJoin] REAPPROVE requestId={} notificationId={} approverUserId={}",
            requestId, notificationId, approverUserId);
    }

    private PermissionRequestEntity validateAndGetWorkspaceRequest(String requestId, Long approverUserId) {
        ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
        PermissionRequestEntity request = baseMapper.selectById(requestId);
        ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
        if (!STATUS_PENDING.equals(request.getStatus())) {
            log.warn("[lbl][2423-空间站审批][WorkspaceJoin] validate alreadyProcessed requestId={} status={}",
                request.getId(), request.getStatus());
            ExceptionUtil.isTrue(false, PermissionRequestException.REQUEST_ALREADY_PROCESSED);
        }
        boolean isSpaceAdmin = spaceQueryManager.isUserSpaceAdmin(approverUserId, request.getSpaceId());
        ExceptionUtil.isTrue(isSpaceAdmin, PermissionRequestException.INSUFFICIENT_PERMISSIONS);
        return request;
    }

    private void validateWorkspaceRequestForApprover(String requestId, Long approverUserId) {
        ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
        PermissionRequestEntity request = baseMapper.selectById(requestId);
        ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
        boolean isSpaceAdmin = spaceQueryManager.isUserSpaceAdmin(approverUserId, request.getSpaceId());
