    // ========== Approve / Reject / Ignore / Reapprove (workspace) ==========

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void approveWorkspaceByRequestId(String requestId, Long notificationId, Long approverUserId) {
        PermissionRequestEntity request = validateAndGetWorkspaceRequest(requestId, approverUserId);

        UserSimpleInfoVo approverInfo = getApproverInfo(approverUserId);
        String approverNickName = approverInfo != null && approverInfo.getNickName() != null ? approverInfo.getNickName() : "";
        String approverUuid = approverInfo != null && approverInfo.getUuid() != null ? approverInfo.getUuid() : String.valueOf(approverUserId);

        // Add applicant to space root team (teamId=0L)
        String workspaceId = request.getSpaceId();
        try {
            apitableGrpcClientService.addUsersToTeam(workspaceId,
                List.of(request.getApplicantUserId()), 0L, true);
            log.info("[lbl][2423-空间站审批][WorkspaceJoin][APPROVE] addUsersToTeam ok workspaceId={} applicantUserId={}",
                workspaceId, request.getApplicantUserId());
        } catch (Exception e) {
            log.error("[lbl][2423-空间站审批][WorkspaceJoin][APPROVE] addUsersToTeam failed workspaceId={} applicantUserId={} error={}",
                workspaceId, request.getApplicantUserId(), e.getMessage(), e);
            throw new BusinessException("加入空间站失败: " + e.getMessage());
        }

        // Update request status
        int rows = baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);
        log.info("[lbl][2423-空间站审批][WorkspaceJoin] APPROVE DB updateStatus requestId={} rows={}", request.getId(), rows);

        // Update notification extras + mark read
        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_APPROVED,
            approverUuid, approverNickName);
        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);

        // Mark other admins' notifications as read
        markOtherWorkspaceRecipientNotificationsRead(notificationId, request, approverUserId);

        // Notify applicant
        notifyWorkspaceApplicantResultAsync(request, STATUS_APPROVED, approverUuid, approverNickName);

        log.info("[lbl][2423-空间站审批][WorkspaceJoin] APPROVE done requestId={} approverUserId={} applicantUserId={} workspaceId={}",
            request.getId(), approverUserId, request.getApplicantUserId(), workspaceId);
    }

