    // ========== Validation Helpers ==========

    /**
     * Validates requestId exists and approver is admin. Does NOT check PENDING status.
     * Used for reapprove, which can act on already-processed requests.
     */
    private void validateRequestForApprover(String requestId, Long approverUserId) {
        if (requestId == null || requestId.isBlank()) {
            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
        }
        PermissionRequestEntity request = baseMapper.selectById(requestId);
        if (request == null) {
            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
        }
        validateApproverIsAuthorized(approverUserId, request.getSpaceId(), request.getDocumentId());
    }

    private PermissionRequestEntity validateAndGetRequest(String requestId, Long approverUserId) {
        if (requestId == null || requestId.isBlank()) {
            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
        }
        PermissionRequestEntity request = baseMapper.selectById(requestId);
        if (request == null) {
            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
        }
        if (!STATUS_PENDING.equals(request.getStatus())) {
            log.warn("[1822-PermApply] validate alreadyProcessed requestId={} status={}",
                request.getId(), request.getStatus());
            ExceptionUtil.isTrue(false, PermissionRequestException.REQUEST_ALREADY_PROCESSED);
        }
        validateApproverIsAuthorized(approverUserId, request.getSpaceId(), request.getDocumentId());
        return request;
    }

    /**
     * Approver is authorized if they are a space admin (MANAGE_WORKBENCH) OR a document manager (MANAGE role on document).
     * Both groups receive the permission-apply notification and should be able to act on it.
     */
    private void validateApproverIsAuthorized(Long approverUserId, String spaceId, String documentId) {
        boolean isSpaceAdmin = spaceQueryManager.isUserSpaceAdmin(approverUserId, spaceId);
        if (isSpaceAdmin) {
            log.info("[1822-PermApply] validateApprover passed as spaceAdmin approverUserId={} spaceId={}", approverUserId, spaceId);
            return;
        }
        List<Long> docManagers = getDocumentManagerUserIds(documentId, spaceId);
        boolean isDocManager = docManagers.contains(approverUserId);
        log.info("[1822-PermApply] validateApprover isSpaceAdmin={} isDocManager={} approverUserId={} documentId={}",
            isSpaceAdmin, isDocManager, approverUserId, documentId);
        ExceptionUtil.isTrue(isDocManager, PermissionRequestException.INSUFFICIENT_PERMISSIONS);
    }

    private UserSimpleInfoVo getApproverInfo(Long approverUserId) {
        try {
            return apitableGrpcClientService.getUserById(approverUserId);
        } catch (Exception e) {
            return null;
        }
    }

    private Long parseSpaceNodeId(String documentId) {
        if (documentId == null) return null;
        // Always look up by appSpaceNodeId column first.
        // OnlyOffice nodes (PPT/Excel/Word) use a numeric OnlyOffice fileId as appSpaceNodeId,
        // which must NOT be treated as the collabspace pk.
        Long byAppNodeId = getSpaceNodeIdByAppNodeId(documentId);
        if (byAppNodeId != null) return byAppNodeId;
        // Fallback: if documentId is a pure numeric string, treat as spaceNodeId pk.
        try {
            return Long.parseLong(documentId);
        } catch (NumberFormatException e) {
            return null;
        }
    }

    private Long getSpaceNodeIdByAppNodeId(String appNodeId) {
        try {
            List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIdsAllStatus(Collections.singletonList(appNodeId));
            if (CollUtil.isNotEmpty(nodes)) {
                return nodes.get(0).getId();
            }
        } catch (Exception e) {
            log.warn("[1822-PermApply] getSpaceNodeIdByAppNodeId failed appNodeId={}", appNodeId, e);
        }
        return null;
    }

    /**
     * Returns the collabspace userIds of all users who have explicit MANAGE permission on the document.
     * Handles both member-type (individual) and team-type (department) unit entries in control_role.
     */
    private List<Long> getDocumentManagerUserIds(String documentId, String spaceId) {
        try {
            Long spaceNodeId = parseSpaceNodeId(documentId);
            if (spaceNodeId == null) return List.of();

            List<ControlRoleEntity> roles = controlRoleService.getByControlId(spaceNodeId.toString());
            List<Long> managerUnitIds = roles.stream()
                .filter(r -> MANAGER.equals(r.getRoleCode()))
                .map(ControlRoleEntity::getUnitId)
                .toList();

            if (CollUtil.isEmpty(managerUnitIds)) return List.of();

            List<NodeRoleUnit> nodeRoleUnits = apitableGrpcClientService.getNodeRoleUnitList(spaceId, managerUnitIds);

            Set<Long> userIds = new HashSet<>();
            List<Long> memberTypeRefIds = new ArrayList<>(); // memberId for unitType=3

            for (NodeRoleUnit unit : nodeRoleUnits) {
                if (unit.getUnitRefId() == null) continue;
                Integer unitType = unit.getUnitType();
                if (unitType != null && unitType == 1) {
                    // Team/department: expand to all members
                    List<UserSimpleInfoVo> members = apitableGrpcClientService.selectMembersByTeamId(spaceId, unit.getUnitRefId());
                    members.stream().filter(m -> m.getId() != null).forEach(m -> userIds.add(m.getId()));
                } else if (unitType != null && unitType == 3) {
                    // Individual member: collect memberId for batch email lookup
                    memberTypeRefIds.add(unit.getUnitRefId());
                }
            }

            // Resolve member-type units: memberId → email → userId
            if (!memberTypeRefIds.isEmpty()) {
                IPage<SpaceMemberVo> memberPage = apitableGrpcClientService.getSpaceMembers(spaceId, 1, 999);
                Map<String, String> memberIdToEmail = memberPage.getRecords().stream()
                    .filter(m -> m.getMemberId() != null && m.getEmail() != null)
                    .collect(Collectors.toMap(SpaceMemberVo::getMemberId, SpaceMemberVo::getEmail, (a, b) -> a));

                List<String> emails = memberTypeRefIds.stream()
                    .map(refId -> memberIdToEmail.get(String.valueOf(refId)))
                    .filter(Objects::nonNull)
                    .toList();

                if (!emails.isEmpty()) {
                    apitableGrpcClientService.getUserByEmails(emails).stream()
                        .filter(u -> u.getId() != null)
                        .forEach(u -> userIds.add(u.getId()));
                }
            }

            log.info("[1822-PermApply] getDocumentManagerUserIds documentId={} managerUnitCount={} resolvedUserCount={}",
                documentId, managerUnitIds.size(), userIds.size());
            return new ArrayList<>(userIds);
        } catch (Exception e) {
            log.warn("[1822-PermApply] getDocumentManagerUserIds failed documentId={} error={}", documentId, e.getMessage());
            return List.of();
        }
    }

    /**
     * After one admin approves/rejects, mark all other admin and doc-manager recipients' notifications as read.
     * The apply notification is a shared record in apitable — the same notificationId covers all recipients,
     * so setNotificationRead(notificationId, otherUserId, true) marks it read for each of them individually.
     */
    private void markOtherRecipientNotificationsRead(Long notificationId, PermissionRequestEntity request,
                                                      Long approverUserId) {
        try {
            List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(request.getSpaceId());
            List<Long> docManagerUserIds = getDocumentManagerUserIds(request.getDocumentId(), request.getSpaceId());

            Set<Long> others = new LinkedHashSet<>();
            others.addAll(adminUserIds);
            others.addAll(docManagerUserIds);
            others.remove(request.getApplicantUserId());
            others.remove(approverUserId);

            for (Long userId : others) {
                apitableGrpcClientService.setNotificationRead(notificationId, userId, true);
            }
            log.info("[1822-PermApply] markOtherRecipients notificationId={} count={} requestId={}",
                notificationId, others.size(), request.getId());
        } catch (Exception e) {
            log.warn("[1822-PermApply] markOtherRecipients failed notificationId={} requestId={} error={}",
                notificationId, request.getId(), e.getMessage());
        }
    }

    private String mapPermissionTypeToNodeRole(String requestedPermissionType) {
        return switch (requestedPermissionType) {
            case "READ" -> READER;
            case "EDIT" -> EDITOR;
            case "MANAGE" -> MANAGER;
            default -> READER;
        };
    }

    private String mapPermissionTypeToLabel(String requestedPermissionType) {
        if (requestedPermissionType == null) return "";
        return switch (requestedPermissionType) {
            case "READ" -> "查看";
            case "EDIT" -> "编辑";
            case "MANAGE" -> "管理";
            default -> requestedPermissionType;
        };
    }

    @Async
    public void notifyApplicantResultAsync(PermissionRequestEntity request, String status,
                                            String approverUuid, String approverNickName) {
        try {
            String templateId = STATUS_APPROVED.equals(status) ? "permission_approved" : "permission_rejected";
            // Use documentName stored at submit time; fall back to re-query only if null/empty
            String documentName = request.getDocumentName();
            if (documentName == null || documentName.isBlank()) {
                try {
                    SpaceNodeEntity node = getSpaceNodeByNodeIdSafe(request.getDocumentId());
                    documentName = node != null ? node.getName() : "";
                } catch (Exception e) {
                    log.debug("[1822-PermApply] notifyApplicantResult get node name failed documentId={}", request.getDocumentId());
                    documentName = "";
                }
            }

            Map<String, Object> extras = new HashMap<>();
            extras.put("requestId", request.getId());
            extras.put("documentId", request.getDocumentId());
            extras.put("documentName", documentName);
            extras.put("status", status);
            extras.put("approverUserId", approverUuid);
            extras.put("approverNickName", approverNickName != null ? approverNickName : "");

            Map<String, Object> bodyMap = new HashMap<>();
            bodyMap.put(BODY_EXTRAS, extras);
            String bodyJson = JSONUtil.toJsonStr(bodyMap);

            apitableGrpcClientService.createNotification(
                templateId,
                approverUuid,
                Collections.singletonList(String.valueOf(request.getApplicantUserId())),
                request.getDocumentId(),
                request.getSpaceId(),
                bodyJson,
                false
            );
            log.info("[1822-PermApply] notifyApplicantResult requestId={} status={} applicantUserId={}",
                request.getId(), status, request.getApplicantUserId());
        } catch (Exception e) {
            log.error("[1822-PermApply] ERROR notifyApplicantResult requestId={} status={} error={}",
                request.getId(), status, e.getMessage(), e);
        }
    }

    private PermissionRequestVo buildVo(PermissionRequestEntity entity, String documentName, String spaceName) {
        return PermissionRequestVo.builder()
            .id(entity.getId())
            .documentId(entity.getDocumentId())
            .documentName(documentName)
            .spaceId(entity.getSpaceId())
            .spaceName(spaceName)
            .requestedPermissionType(entity.getRequestedPermissionType())
            .status(entity.getStatus())
            .createdAt(entity.getCreatedAt())
            .build();
    }
}

