    @Override
    public List<PermissionRequestVo> getMyRequests(Long userId, String status, int page, int pageSize) {
        int offset = (page - 1) * pageSize;
        List<PermissionRequestEntity> entities = baseMapper.selectByApplicantUserId(userId, status, offset, pageSize);
        if (CollUtil.isEmpty(entities)) {
            return Collections.emptyList();
        }
        return entities.stream().map(e -> {
            String docName = "";
            String spaceName = "";
            try {
                SpaceNodeEntity node = getSpaceNodeByNodeIdSafe(e.getDocumentId());
                docName = node != null ? node.getName() : "";
            } catch (Exception ex) {
                log.debug("[1822-PermApply] Node not found: {}", e.getDocumentId());
            }
            try {
                SpaceEntity space = spaceService.getBySpaceId(e.getSpaceId());
                spaceName = space != null && space.getName() != null ? space.getName() : "";
            } catch (Exception ex) {
                log.debug("[1822-PermApply] Space not found: {}", e.getSpaceId());
            }
            return buildVo(e, docName, spaceName);
        }).collect(Collectors.toList());
    }

