    private PermissionRequestEntity validateAndGetWorkspaceRequest(String requestId, Long approverUserId) {
        ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
        PermissionRequestEntity request = baseMapper.selectById(requestId);
        ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
        if (!STATUS_PENDING.equals(request.getStatus())) {
            log.warn("[lbl][2423-空间站审批][WorkspaceJoin] validate alreadyProcessed requestId={} status={}",
                request.getId(), request.getStatus());
            ExceptionUtil.isTrue(false, PermissionRequestException.REQUEST_ALREADY_PROCESSED);
        }
        boolean isSpaceAdmin = spaceQueryManager.isUserSpaceAdmin(approverUserId, request.getSpaceId());
        ExceptionUtil.isTrue(isSpaceAdmin, PermissionRequestException.INSUFFICIENT_PERMISSIONS);
        return request;
    }

    private void validateWorkspaceRequestForApprover(String requestId, Long approverUserId) {
        ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
        PermissionRequestEntity request = baseMapper.selectById(requestId);
        ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
        boolean isSpaceAdmin = spaceQueryManager.isUserSpaceAdmin(approverUserId, request.getSpaceId());
        ExceptionUtil.isTrue(isSpaceAdmin, PermissionRequestException.INSUFFICIENT_PERMISSIONS);
    }

    private void markOtherWorkspaceRecipientNotificationsRead(Long notificationId,
                                                               PermissionRequestEntity request,
                                                               Long approverUserId) {
        try {
            List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(request.getSpaceId());
            Set<Long> others = new LinkedHashSet<>(adminUserIds);
            others.remove(request.getApplicantUserId());
            others.remove(approverUserId);

            for (Long userId : others) {
                apitableGrpcClientService.setNotificationRead(notificationId, userId, true);
            }
            log.info("[lbl][2423-空间站审批][WorkspaceJoin] markOtherRecipients notificationId={} count={} requestId={}",
                notificationId, others.size(), request.getId());
        } catch (Exception e) {
            log.warn("[lbl][2423-空间站审批][WorkspaceJoin] markOtherRecipients failed notificationId={} requestId={} error={}",
                notificationId, request.getId(), e.getMessage());
        }
    }

