    // ========== Approve / Reject (by requestId) ==========

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void approveByRequestId(String requestId, Long notificationId, Long approverUserId) {
        PermissionRequestEntity request = validateAndGetRequest(requestId, approverUserId);

        UserSimpleInfoVo approverInfo = getApproverInfo(approverUserId);
        String approverNickName = approverInfo != null && approverInfo.getNickName() != null ? approverInfo.getNickName() : "";
        String approverUuid = approverInfo != null && approverInfo.getUuid() != null ? approverInfo.getUuid() : String.valueOf(approverUserId);

        // Get applicant unitId
        UnitMemberVo applicantMember = apitableGrpcClientService.findUnitMemberVo(
                List.of(request.getApplicantUserId()), request.getSpaceId())
            .stream().findFirst().orElse(null);
        ExceptionUtil.isNotNull(applicantMember, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
        Long unitId = applicantMember.getUnitId();
        ExceptionUtil.isNotNull(unitId, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);

        // Map permission type to node role
        String nodeRole = mapPermissionTypeToNodeRole(request.getRequestedPermissionType());
        log.info("[1822-PermApply] APPROVE mapRole requestId={} requestedType={} nodeRole={} unitId={} documentId={}",
            request.getId(), request.getRequestedPermissionType(), nodeRole, unitId, request.getDocumentId());

        // Add node role
        Long spaceNodeId = parseSpaceNodeId(request.getDocumentId());
        if (spaceNodeId != null) {
            nodeRoleUpdateManager.addNodeRole(approverUserId, request.getSpaceId(), spaceNodeId, nodeRole,
                Collections.singletonList(unitId));
            log.info("[1822-PermApply] APPROVE addNodeRole ok spaceNodeId={} nodeRole={} unitId={}", spaceNodeId, nodeRole, unitId);
        } else {
            log.warn("[1822-PermApply] APPROVE WARN spaceNodeId not found for documentId={}, node permission grant SKIPPED",
                request.getDocumentId());
        }

        // Update permission request status in collabspace
        int rows = baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);
        log.info("[1822-PermApply] APPROVE DB updateStatus requestId={} status=APPROVED approverUserId={} rows={}",
            request.getId(), approverUserId, rows);

        // Update notification extras in apitable (via gRPC) — updates shared notification record for all recipients
        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_APPROVED,
            approverUuid, approverNickName);

        // Mark approver's own notification as read
        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);

        // Mark all other admin/manager recipients' notifications as read (same shared notificationId)
        markOtherRecipientNotificationsRead(notificationId, request, approverUserId);

        // Notify applicant that their request was approved
        notifyApplicantResultAsync(request, STATUS_APPROVED, approverUuid, approverNickName);

        log.info("[1822-PermApply] APPROVE done requestId={} approverUserId={} applicantUserId={} documentId={} nodeRole={}",
            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId(), nodeRole);
    }

